 {"id":"coding_agent_session_search-jv3y","title":"[Task] Create full_coverage_validation.sh Master Script","description":"## Task: Create Full Coverage Validation E2E Script

Create `scripts/e2e/full_coverage_validation.sh` - the master script that validates all test coverage improvements.

### Purpose
Single script that:
1. Runs all unit tests (connector, query, security)
2. Runs all new E2E scripts
3. Validates JSONL logging compliance
4. Generates comprehensive coverage report
5. Produces summary for CI

### Script Structure
```bash
#\!/bin/bash
set -euo pipefail
source scripts/lib/e2e_log.sh

SCRIPT_NAME="full_coverage_validation"
e2e_init "shell" "$SCRIPT_NAME"
e2e_run_start

echo "=== Full Test Coverage Validation ==="
echo "Started: $(date)"

# Phase 1: Unit Tests
e2e_phase_start "unit_tests" "Running all unit tests"
e2e_test_start "connector_edge_cases" "unit"
cargo test edge_case_tests --no-fail-fast 2>&1 | tee test-results/unit_tests.log
if [ ${PIPESTATUS[0]} -eq 0 ]; then
    e2e_test_pass "connector_edge_cases" "unit" "$duration"
else
    e2e_test_fail "connector_edge_cases" "unit" "Unit tests failed" "$duration"
fi

e2e_test_start "query_parsing" "unit"
cargo test search::query::tests --no-fail-fast 2>&1 | tee -a test-results/unit_tests.log
# ... status handling ...

e2e_test_start "security_paths" "unit"
cargo test pages::verify::tests --no-fail-fast 2>&1 | tee -a test-results/unit_tests.log
# ... status handling ...
e2e_phase_end "unit_tests"

# Phase 2: E2E Scripts
e2e_phase_start "e2e_scripts" "Running E2E test scripts"
for script in connector_stress query_parser_e2e security_paths_e2e; do
    e2e_test_start "$script" "e2e"
    if ./scripts/e2e/${script}.sh; then
        e2e_test_pass "$script" "e2e" "$duration"
    else
        e2e_test_fail "$script" "e2e" "Script failed" "$duration"
    fi
done
e2e_phase_end "e2e_scripts"

# Phase 3: JSONL Validation
e2e_phase_start "jsonl_validation" "Validating JSONL compliance"
for jsonl in test-results/e2e/shell_*.jsonl; do
    e2e_test_start "validate_$(basename $jsonl)" "validation"
    if ./scripts/tests/validate-e2e-jsonl.sh "$jsonl"; then
        e2e_test_pass "validate_$(basename $jsonl)" "validation" "$duration"
    else
        e2e_test_fail "validate_$(basename $jsonl)" "validation" "Invalid JSONL" "$duration"
    fi
done
e2e_phase_end "jsonl_validation"

# Phase 4: Coverage Report
e2e_phase_start "coverage" "Generating coverage report"
cargo +nightly llvm-cov --lib --html --output-dir test-results/coverage 2>&1 || true
e2e_phase_end "coverage"

# Summary
e2e_emit_metric "total_tests" "$total"
e2e_emit_metric "passed_tests" "$passed"
e2e_emit_metric "failed_tests" "$failed"

e2e_run_end "$total" "$passed" "$failed" "$skipped" "$total_duration"

# Exit with appropriate code
if [ "$failed" -gt 0 ]; then
    echo "FAILED: $failed tests failed"
    exit 1
fi
echo "SUCCESS: All $passed tests passed"
```

